package main

import (
    "errors"
    "fmt"
)

// ---- Custom error types ----
type NotFoundError struct {
    Resource string
    ID       string
}

func (e NotFoundError) Error() string {
    return fmt.Sprintf("%s with ID '%s' not found", e.Resource, e.ID)
}

type ValidationError struct {
    Field   string
    Value   interface{}
    Reason  string
}

func (e ValidationError) Error() string {
    return fmt.Sprintf("validation failed for field '%s' (value: %v): %s",
        e.Field, e.Value, e.Reason)
}

type DatabaseError struct {
    Operation string
    Err       error
}

func (e DatabaseError) Error() string {
    return fmt.Sprintf("database error in %s: %v", e.Operation, e.Err)
}

func (e DatabaseError) Unwrap() error {
    return e.Err
}

// ---- Error constants ----
var ErrPlayerNotFound = errors.New("player not found")
var ErrInvalidInput = errors.New("invalid input")

// ---- Functions with custom errors ----
func findPlayer(id string) (string, error) {
    if id == "" {
        return "", ValidationError{
            Field:  "id",
            Value:  id,
            Reason: "cannot be empty",
        }
    }
    if id == "123" {
        return "Hero", nil
    }
    return "", NotFoundError{
        Resource: "player",
        ID:       id,
    }
}

func getPlayer(id string) (string, error) {
    result, err := findPlayer(id)
    if err != nil {
        return "", DatabaseError{
            Operation: "getPlayer",
            Err:       err,
        }
    }
    return result, nil
}

// ---- Error checking ----
func main() {
    // ---- Custom errors ----
    fmt.Println("=== Custom Errors ===")

    _, err := findPlayer("")
    if err != nil {
        fmt.Println("Error:", err)

        if ve, ok := err.(ValidationError); ok {
            fmt.Printf("Field: %s, Value: %v, Reason: %s\n",
                ve.Field, ve.Value, ve.Reason)
        }
    }

    _, err = findPlayer("999")
    if err != nil {
        fmt.Println("Error:", err)

        if ne, ok := err.(NotFoundError); ok {
            fmt.Printf("Resource: %s, ID: %s\n", ne.Resource, ne.ID)
        }
    }

    // ---- Wrapped errors ----
    fmt.Println("\n=== Wrapped Errors ===")

    _, err = getPlayer("999")
    if err != nil {
        fmt.Println("Error:", err)

        if de, ok := err.(DatabaseError); ok {
            fmt.Println("Operation:", de.Operation)
            fmt.Println("Underlying:", de.Err)
        }
    }

    // ---- errors.Is with wrapped errors ----
    fmt.Println("\n=== errors.Is ===")

    err = getPlayer("")
    if errors.Is(err, ErrInvalidInput) {
        fmt.Println("Invalid input error detected")
    }

    // ---- Error chains ----
    fmt.Println("\n=== Error Chain ===")
    err = getPlayer("999")

    // Unwrap multiple times
    for err != nil {
        fmt.Println("Error:", err)
        err = errors.Unwrap(err)
    }
}

